#!/usr/bin/env python3
import numpy as np
import torch
from torch.utils.data import Dataset

class TrafficDataset(Dataset):
    def __init__(self, data_path, adj_path, input_len=12, pred_len=12, stride=1):
        # Load data
        self.data = np.load(data_path)
        self.adj = np.load(adj_path)

        self.input_len = input_len
        self.pred_len = pred_len
        self.stride = stride

        # Create sliding windows
        self.samples = []
        for i in range(0, len(self.data) - input_len - pred_len + 1, stride):
            x = self.data[i:i+input_len]
            y = self.data[i+input_len:i+input_len+pred_len]
            self.samples.append((x, y))

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        x, y = self.samples[idx]
        return torch.FloatTensor(x), torch.FloatTensor(y)

def get_dataloaders(train_path, val_path, adj_path, input_len=12, pred_len=12, batch_size=32):
    train_dataset = TrafficDataset(train_path, adj_path, input_len, pred_len)
    val_dataset = TrafficDataset(val_path, adj_path, input_len, pred_len)

    train_loader = torch.utils.data.DataLoader(train_dataset, batch_size=batch_size, shuffle=True)
    val_loader = torch.utils.data.DataLoader(val_dataset, batch_size=batch_size, shuffle=False)

    return train_loader, val_loader
